INSERT INTO `wp_comments` VALUES (1,1,'Un comentator WordPress','wapuu@wordpress.example','https://wordpress.org/','','2017-09-30 10:29:56','2017-09-30 10:29:56','Bună, acesta este un comentariu.\nPentru a începe moderarea, editarea și ștergerea comentariilor, te rog vizitează ecranul Comentarii din panoul de control.\nAvatarele comentatorului provin din <a href=\"https://gravatar.com\">Gravatar</a>.',0,'1','','comment',0,0),(2,1,'nume','email@yahoo.ro','','5.13.182.80','2017-10-15 18:55:21','2017-10-15 18:55:21','Acesta este un raspuns',0,'1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/61.0.3163.100 Safari/537.36','comment',0,0),(3,160,'nume','','http://s','::1','2022-05-13 12:04:06','2022-05-13 12:04:06','com',0,'1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/101.0.4951.54 Safari/537.36','comment',0,0);
