LOCK TABLES `wp_posts` WRITE;
/*!40000 ALTER TABLE `wp_posts` DISABLE KEYS */;
INSERT INTO `wp_posts` VALUES (1,1,'2017-09-30 10:29:56','2017-09-30 10:29:56','<!-- wp:image {\"sizeSlug\":\"large\",\"linkDestination\":\"custom\"} -->\n<figure class=\"wp-block-image size-large\"><a href=\"/2017/09/30/salut-lume/\"><img src=\"https://192.168.1.3/wp-content/uploads/2017/09/1.jpg\" alt=\"\"/></a></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p>Magistraţii Tribunalului Bucureşti au decis, joi, că Victor Ponta trebuie să îi plătească daune morale de 10.000 de lei lui Lucian Isar, soţul Alinei Gorghiu, după ce fostul premier a spus că în perioada în care era ministru pentru mediul de afaceri şi IMM-uri Lucian Isar ar fi cerut mită de la o companie americană pentru realizarea unei investiţii în România. În prima instanţă, magistraţii hotărăseră ca Ponta să îi achite lui Isar daune de 20.000 de lei.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Distribuie pe Facebook Distribuie pe Twitter Distribuie pe Email<br>\"Admite apel declarat de Ponta Victor. Schimbă în parte sentinţa civilă apelată, în sensul că stabileşte cuantumul daunelor morale la 10.000 de lei\", este decizia luată joi de către magistraţii Tribunalului Bucureşti.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Hotărârea instanţei este definitivă.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>În luna aprilie a acestui an, Judecătoria Sector 2 a stabilit că fostul premier Victor Ponta trebuie să-i plătească lui Lucian Isar suma de 20.000 de lei. Decizia instanţei nu a fost definitivă, fiind atacată de Victor Ponta.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Într-o postare de pe Facebook din februarie 2016, Ponta spunea că l-a demis pe Lucian Isar, care ocupa funcţia de ministru pentru Relaţia cu mediul de afaceri, după ce a fost informat de serviciile secrete despre intenţia acestuia de a cere mită de la o firma americană.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>\"În aproape patru ani de activitate ca prim-ministru a fost o singură ocazie în care am primit direct informare de la instituţiile specializate ale statului despre o tentativă clară de corupţie din partea unui ministru - Lucian Isar care a cerut avantaje personale de la un mare investitor american în schimbul sprijinului pentru implementarea unui proiect important în România.\"</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>În urmă acestei postări, Isar a decis să-l dea în judecată pe Victor Ponta pentru calomnie şi i-a cerut 100.000 de lei daune morale.</p>\n<!-- /wp:paragraph -->','Victor Ponta trebuie să îi plătească lui Lucian Isar daune morale de 10.000 de lei. Decizia instanţei este definitivă','','publish','open','open','','salut-lume','','','2022-05-15 19:26:57','2022-05-15 19:26:57','',0,'http://alex/wordpress/?p=1',0,'post','',2),(23,1,'2017-09-30 11:07:22','2017-09-30 11:07:22','pagina\r\n\r\n&nbsp;','Home','','publish','closed','closed','','site-stiri','','','2017-10-11 18:28:09','2017-10-11 18:28:09','',0,'http://alex/wordpress/?page_id=23',0,'page','',0),(24,1,'2017-09-30 11:07:22','2017-09-30 11:07:22','','Site știri','','inherit','closed','closed','','23-revision-v1','','','2017-09-30 11:07:22','2017-09-30 11:07:22','',23,'http://alex/wordpress/2017/09/30/23-revision-v1/',0,'revision','',0),(26,1,'2017-09-30 13:48:29','2017-09-30 13:48:29','adawdawdaw','Site știri','','inherit','closed','closed','','23-revision-v1','','','2017-09-30 13:48:29','2017-09-30 13:48:29','',23,'http://alex/wordpress/2017/09/30/23-revision-v1/',0,'revision','',0),(29,1,'2017-09-30 14:04:39','2017-09-30 14:04:39','adawdawdaw\r\n\r\nyujty','Site știri','','inherit','closed','closed','','23-revision-v1','','','2017-09-30 14:04:39','2017-09-30 14:04:39','',23,'http://alex/wordpress/2017/09/30/23-revision-v1/',0,'revision','',0),(30,1,'2017-09-30 14:09:14','2017-09-30 14:09:14','adawdawdaw\r\n\r\nyujty','','','inherit','closed','closed','','23-revision-v1','','','2017-09-30 14:09:14','2017-09-30 14:09:14','',23,'http://alex/wo